import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from "./componentes/Topo";
import Rodape from "./componentes/Rodape" ;

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [etapa, setEtapa] = useState('vitrine'); 
  const [modoCadastro, setModoCadastro] = useState(false);
  const [usuario, setUsuario] = useState(null);
  const [formaPagamento, setFormaPagamento] = useState('');
  const [pedidoFinalizado, setPedidoFinalizado] = useState(null);

  const [formData, setFormData] = useState({
    nome: '', email: '', senha: '', cpf: '', telefone: '', cep: '', endereco: ''
  });

  useEffect(() => {
    fetch("http://localhost:3001/produtos")
      .then(res => res.json())
      .then(dados => setProdutos(dados))
      .catch(err => console.error(err));
  }, []);

  const adicionarAoCarrinho = (p) => {
    const ex = carrinho.find(x => x.id === p.id);
    if (ex) {
      setCarrinho(carrinho.map(x => x.id === p.id ? { ...ex, qtd: ex.qtd + 1 } : x));
    } else {
      setCarrinho([...carrinho, { ...p, qtd: 1 }]);
    }
    setEtapa('carrinho');
  };

  const alterarQtd = (id, op) => {
    setCarrinho(carrinho.map(i => i.id === id ? { ...i, qtd: op === '+' ? i.qtd + 1 : Math.max(1, i.qtd - 1) } : i));
  };

  const totalProdutos = carrinho.reduce((acc, i) => acc + (i.valor * i.qtd), 0);
  const valorFrete = formaPagamento === 'pix' ? 0 : 15.00;
  const totalFinal = totalProdutos + valorFrete;

  // --- FUNÇÕES DE BANCO ---
  const handleLogin = () => {
    fetch("http://localhost:3001/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email: formData.email, senha: formData.senha })
    })
    .then(res => res.ok ? res.json() : Promise.reject())
    .then(user => { setUsuario(user); setEtapa('checkout'); })
    .catch(() => alert("Usuário não encontrado ou senha incorreta!"));
  };

  const handleCadastro = () => {
    fetch("http://localhost:3001/cadastrar", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(formData)
    })
    .then(res => res.ok ? res.json() : Promise.reject())
    .then(user => { setUsuario(user); setEtapa('checkout'); })
    .catch(() => alert("Erro ao cadastrar! CPF ou E-mail já podem existir no banco."));
  };

  const finalizarNoBanco = () => {
    const numP = Math.floor(Math.random() * 900000);
    fetch("http://localhost:3001/finalizar-pedido", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id_pedido: numP, itens: carrinho })
    })
    .then(() => {
      setPedidoFinalizado({ numero: numP, total: totalFinal, pagamento: formaPagamento });
      setEtapa('sucesso');
      setCarrinho([]);
    });
  };

  return (
    <div className="App">
      <Topo totalItens={carrinho.length} abrirCarrinho={() => setEtapa('carrinho')} temPedido={!!pedidoFinalizado} />

      <main className="conteudo-principal">
        
        {/* 1. VITRINE */}
        {etapa === 'vitrine' && (
          <div className="grid-produtos">
            {produtos.map(p => (
              <div key={p.id} className="card">
                <img src={p.imagem_url} alt={p.produto} />
                <h3>{p.produto}</h3>
                <p className="preco">R$ {parseFloat(p.valor).toFixed(2)}</p>
                <button onClick={() => adicionarAoCarrinho(p)}>Comprar</button>
              </div>
            ))}
          </div>
        )}

        {/* 2. CARRINHO */}
        {etapa === 'carrinho' && (
          <div className="container-venda">
            <h2>🛒 Meu Carrinho</h2>
            {carrinho.map(i => (
              <div key={i.id} className="item-lista">
                <span>{i.produto}</span>
                <div>
                  <button onClick={() => alterarQtd(i.id, '-')}>-</button>
                  <span style={{margin:'0 10px'}}>{i.qtd}</span>
                  <button onClick={() => alterarQtd(i.id, '+')}>+</button>
                </div>
                <span>R$ {(i.valor * i.qtd).toFixed(2)}</span>
              </div>
            ))}
            <h3>Subtotal: R$ {totalProdutos.toFixed(2)}</h3>
            <button className="btn-v" onClick={() => setEtapa('vitrine')}>Voltar</button>
            <button className="btn-p" onClick={() => setEtapa('login')}>Finalizar Pedido</button>
          </div>
        )}

        {/* 3. LOGIN / CADASTRO */}
        {etapa === 'login' && (
          <div className="container-venda">
            <h2>{modoCadastro ? "📝 Cadastrar" : "🔐 Entrar"}</h2>
            <input type="email" placeholder="E-mail" className="in-v" onChange={e => setFormData({...formData, email: e.target.value})} />
            <input type="password" placeholder="Senha" className="in-v" onChange={e => setFormData({...formData, senha: e.target.value})} />
            
            {modoCadastro && (
              <>
                <input type="text" placeholder="Nome" className="in-v" onChange={e => setFormData({...formData, nome: e.target.value})} />
                <input type="text" placeholder="CPF" className="in-v" onChange={e => setFormData({...formData, cpf: e.target.value})} />
                <input type="text" placeholder="CEP" className="in-v" onChange={e => setFormData({...formData, cep: e.target.value})} />
                <input type="text" placeholder="Endereço" className="in-v" onChange={e => setFormData({...formData, endereco: e.target.value})} />
                <input type="text" placeholder="Telefone" className="in-v" onChange={e => setFormData({...formData, telefone: e.target.value})} />
              </>
            )}

            <button className="btn-p" onClick={modoCadastro ? handleCadastro : handleLogin}>
              {modoCadastro ? "Confirmar Cadastro" : "Entrar"}
            </button>
            <p onClick={() => setModoCadastro(!modoCadastro)} className="link-troca">
              {modoCadastro ? "Já sou cliente" : "Não tenho conta? Cadastrar"}
            </p>
          </div>
        )}

        {/* 4. CHECKOUT */}
        {etapa === 'checkout' && usuario && (
          <div className="container-venda">
            <h2>📍 Confirmar Entrega</h2>
            <div className="dados-cli">
              <p><strong>Cliente:</strong> {usuario.nome} | <strong>CPF:</strong> {usuario.cpf}</p>
              <p><strong>Endereço:</strong> {usuario.endereco} - {usuario.cep}</p>
              <p><strong>Telefone:</strong> {usuario.telefone}</p>
            </div>
            <h3>💳 Pagamento</h3>
            <select className="in-v" onChange={e => setFormaPagamento(e.target.value)}>
              <option value="">Selecione...</option>
              <option value="pix">Pix (Frete Grátis)</option>
              <option value="credito">Cartão de Crédito</option>
              <option value="debito">Cartão de Débito</option>
            </select>
            <div className="resumo-f">
              <p>Pedido: R$ {totalProdutos.toFixed(2)}</p>
              <p>Frete: R$ {valorFrete.toFixed(2)}</p>
              <hr />
              <h3>Total: R$ {totalFinal.toFixed(2)}</h3>
            </div>
            <button className="btn-p" onClick={finalizarNoBanco}>Confirmar Pedido</button>
          </div>
        )}

        {/* 5. SUCESSO */}
        {etapa === 'sucesso' && (
          <div className="alerta-s">
            <h2>✅ Pedido #{pedidoFinalizado.numero} Realizado!</h2>
            <p>Status: Em Andamento</p>
            <p>Frete: R$ {pedidoFinalizado.pagamento === 'pix' ? "0.00" : "15.00"}</p>
            <h3>Total Pago: R$ {pedidoFinalizado.total.toFixed(2)}</h3>
            <button onClick={() => setEtapa('vitrine')}>Voltar ao Início</button>
          </div>
        )}

      </main>
      <Rodape />
    </div>
  );
}

export default App;
